    17→public final class SeqBoruvka extends AbstractBoruvka implements BoruvkaFactory<SeqComponent, SeqEdge> {
    18→
    19→    protected final Queue<SeqComponent> nodesLoaded = new LinkedList<>();
    20→
    21→    public SeqBoruvka() {
    22→        super();
    23→    }
    24→
