    50→    private void computeBoruvka(final Queue<SeqComponent> nodesLoaded) {
    51→
    52→        SeqComponent loopNode = null;
    53→
    54→        // START OF EDGE CONTRACTION ALGORITHM
    55→        while (!nodesLoaded.isEmpty()) {
    56→
    57→            // poll() removes first element (node loopNode) from the nodesLoaded work-list
    58→            loopNode = nodesLoaded.poll();
    59→
    60→            if (loopNode.isDead) {
    61→                continue; // node loopNode has already been merged
    62→            }
    63→
    64→            final Edge<SeqComponent> e = loopNode.getMinEdge(); // retrieve loopNode's edge with minimum cost
