    70→            other.isDead = true;
    71→            loopNode.merge(other, e.weight()); // merge node other into node loopNode
    72→            nodesLoaded.add(loopNode); // add newly merged loopNode back in the work-list
    73→
    74→        }
    75→        // END OF EDGE CONTRACTION ALGORITHM
    76→        if (loopNode != null) {
