private void computeBoruvka(final Queue<ParComponent> nodesLoaded) throws SuspendableException {
    // Convert to thread-safe queue
    final ConcurrentLinkedQueue<ParComponent> workQueue = new ConcurrentLinkedQueue<>(nodesLoaded);
    nodesLoaded.clear();

    ParComponent loopNode = null;

    // START OF EDGE CONTRACTION ALGORITHM
    while (!workQueue.isEmpty()) {
        // Array to store final result node for checking when algorithm completes
        final ParComponent[] nextLoopNode = new ParComponent[1];

        // Use finish to wait for all async tasks to complete this iteration
        finish(() -> {
            // Process multiple components in parallel
            ParComponent n;
            while ((n = workQueue.poll()) != null) {
                final ParComponent currentNode = n;

                // Check if node is already dead
                if (currentNode.isDead) {
                    continue;
                }

                // Get the minimum edge for this component
                final Edge<ParComponent> e = currentNode.getMinEdge();
                if (e == null) {
                    // This is the final component
                    nextLoopNode[0] = currentNode;
                    break;
                }

                // Process edge contraction in async task
                async(() -> {
                    final ParComponent other = e.getOther(currentNode);
                    other.isDead = true;
                    currentNode.merge(other, e.weight());
                    workQueue.add(currentNode);
                });
            }
        });

        loopNode = nextLoopNode[0];
        if (loopNode == null) {
            // All nodes processed and queue is empty
            break;
        }
    }
    // END OF EDGE CONTRACTION ALGORITHM
    if (loopNode != null) {
        totalEdges = loopNode.totalEdges();
        totalWeight = loopNode.totalWeight();
    }
}

